/*
 * Dynamic memory allocator using segregated free lists.
 *
 * Design:
 * - NUM_CLASSES segregated size classes with explicit doubly-linked free lists.
 * - Size classes use power-of-2 boundaries (class 0: <=32, class 1: 33-64, ...).
 * - Free list heads are stored in the heap at initialization.
 * - LIFO insertion (new free blocks at head) for cache performance.
 * - First-fit search across size classes from smallest to largest.
 * - Boundary-tag coalescing on every free.
 * - Smart realloc: grow in place using adjacent free block or heap extension.
 *
 * Block structure (free):
 *   [header: WSIZE][next_ptr: WSIZE][prev_ptr: WSIZE][...][footer: WSIZE]
 *
 * Block structure (allocated):
 *   [header: WSIZE][payload...][footer: WSIZE]
 *
 * Header/footer format: size | alloc_bit (low bit)
 * All block sizes are multiples of DSIZE = 16.  Minimum block size = 2*DSIZE = 32.
 *
 * Initial heap layout:
 *   [free_lists[0..NUM_CLASSES-1]] [pad] [prologue hdr] [prologue ftr] [epilogue hdr]
 */

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

/*********************************************************
 * NOTE TO STUDENTS: Before you do anything else, please
 * provide your team information in the following struct.
 ********************************************************/
team_t team = {
	/* Team name */
	"BSCS Bench",
	/* First member's full name */
	"BSCS Bench Agent",
	/* First member's NetID */
	"bscs1",
	/* Second member's full name (leave blank if none) */
	"",
	/* Second member's NetID (leave blank if none) */
	""
};

/* Basic constants */
#define WSIZE       sizeof(void *)    /* Word size = 8 bytes on 64-bit */
#define DSIZE       (2 * WSIZE)       /* Double word size = 16 bytes */
#define CHUNKSIZE   (1 << 12)         /* Default heap extension = 4096 bytes */
#define NUM_CLASSES 20                /* Number of segregated size classes */

#define MAX(x, y)  ((x) > (y) ? (x) : (y))
#define MIN(x, y)  ((x) < (y) ? (x) : (y))

/* Pack size and alloc bit into a header/footer word */
#define PACK(size, alloc)  ((size) | (alloc))

/* Read and write a word at address p */
#define GET(p)       (*(uintptr_t *)(p))
#define PUT(p, val)  (*(uintptr_t *)(p) = (val))

/* Read the size and allocated fields from a header/footer at p */
#define GET_SIZE(p)   (GET(p) & ~(DSIZE - 1))
#define GET_ALLOC(p)  (GET(p) & 0x1)

/* Given block payload pointer bp, compute header/footer addresses */
#define HDRP(bp)  ((char *)(bp) - WSIZE)
#define FTRP(bp)  ((char *)(bp) + GET_SIZE(HDRP(bp)) - DSIZE)

/* Given bp, compute next and previous block payload pointers */
#define NEXT_BLKP(bp)  ((char *)(bp) + GET_SIZE(HDRP(bp)))
#define PREV_BLKP(bp)  ((char *)(bp) - GET_SIZE(((char *)(bp) - DSIZE)))

/* Access next/prev free-list pointers stored in a free block's payload */
#define NEXT_FREE(bp)  (*((void **)(bp)))
#define PREV_FREE(bp)  (*((void **)((char *)(bp) + WSIZE)))

/* Global variables (scalars only, per assignment rules) */
static char  *heap_listp;  /* Payload pointer of the prologue block */
static void **free_lists;  /* Points to the free-list-head array in the heap */

/* Internal function prototypes */
static void *coalesce(void *bp);
static void *extend_heap(size_t words);
static void *find_fit(size_t asize);
static void  place(void *bp, size_t asize);
static int   get_class(size_t size);
static void  insert_free(void *bp);
static void  remove_free(void *bp);

/* Heap consistency checker prototypes */
static void checkblock(void *bp);
static void printblock(void *bp);
void checkheap(bool verbose);

/*
 * get_class - Return the segregated free list index for a given block size.
 *
 * Class 0:  size <= 32  (minimum block = 2*DSIZE)
 * Class 1:  33  – 64
 * Class 2:  65  – 128
 * ...
 * Class k:  (2^(k+4), 2^(k+5)]  for k in 1..NUM_CLASSES-2
 * Class 19: catch-all (size > 2^23)
 */
static int
get_class(size_t size)
{
	int c = 0;
	size_t bound = 2 * DSIZE;   /* 32 = minimum block size */

	while (c < NUM_CLASSES - 1 && size > bound) {
		bound <<= 1;
		c++;
	}
	return c;
}

/*
 * insert_free - Insert free block bp at the head of its size-class list (LIFO).
 */
static void
insert_free(void *bp)
{
	int   c    = get_class(GET_SIZE(HDRP(bp)));
	void *head = free_lists[c];

	NEXT_FREE(bp) = head;
	PREV_FREE(bp) = NULL;
	if (head != NULL)
		PREV_FREE(head) = bp;
	free_lists[c] = bp;
}

/*
 * remove_free - Remove free block bp from its size-class list.
 */
static void
remove_free(void *bp)
{
	int   c    = get_class(GET_SIZE(HDRP(bp)));
	void *next = NEXT_FREE(bp);
	void *prev = PREV_FREE(bp);

	if (prev != NULL)
		NEXT_FREE(prev) = next;
	else
		free_lists[c] = next;   /* bp was the head */

	if (next != NULL)
		PREV_FREE(next) = prev;
}

/*
 * mm_init - Initialize the allocator.
 *
 * Heap layout after init:
 *   [free_lists[0..19]] [pad] [pro_hdr] [pro_ftr] [epi_hdr]
 *   ^                         ^
 *   free_lists (heap base)    heap_listp
 */
int
mm_init(void)
{
	void *fl_base;
	char *base;

	/* Allocate space for the free-list array + prologue/epilogue. */
	if ((fl_base = mem_sbrk((NUM_CLASSES + 4) * WSIZE)) == (void *)-1)
		return -1;

	free_lists = (void **)fl_base;

	/* Initialize every free-list head to NULL. */
	for (int i = 0; i < NUM_CLASSES; i++)
		free_lists[i] = NULL;

	/* Build the prologue and epilogue sentinels. */
	base = (char *)fl_base + NUM_CLASSES * WSIZE;
	PUT(base,              0);               /* Alignment padding      */
	PUT(base + WSIZE,      PACK(DSIZE, 1));  /* Prologue header        */
	PUT(base + 2 * WSIZE,  PACK(DSIZE, 1)); /* Prologue footer        */
	PUT(base + 3 * WSIZE,  PACK(0, 1));     /* Epilogue header        */
	heap_listp = base + 2 * WSIZE;

	/* Extend the heap with an initial free block. */
	if (extend_heap(CHUNKSIZE / WSIZE) == NULL)
		return -1;
	return 0;
}

/*
 * mm_malloc - Allocate a block with at least `size` bytes of payload.
 */
void *
mm_malloc(size_t size)
{
	size_t asize;       /* Adjusted block size (header + payload + footer) */
	size_t extendsize;  /* Amount to extend heap if no fit found */
	void  *bp;

	if (size == 0)
		return NULL;

	/* Round up to include overhead and satisfy alignment. */
	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + DSIZE + (DSIZE - 1)) / DSIZE);

	/* Search the segregated free lists. */
	if ((bp = find_fit(asize)) != NULL) {
		place(bp, asize);
		return bp;
	}

	/* No fit found – extend the heap. */
	extendsize = MAX(asize, CHUNKSIZE);
	if ((bp = extend_heap(extendsize / WSIZE)) == NULL)
		return NULL;
	place(bp, asize);
	return bp;
}

/*
 * mm_free - Free the block pointed to by bp.
 */
void
mm_free(void *bp)
{
	size_t size;

	if (bp == NULL)
		return;

	size = GET_SIZE(HDRP(bp));
	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	coalesce(bp);
}

/*
 * mm_realloc - Reallocate ptr to have at least `size` bytes of payload.
 *
 * Tries four strategies in order:
 *   1. Shrink: fits in current block (optionally split remainder).
 *   2. Grow into adjacent free next block.
 *   3. Grow at end of heap (next is epilogue or free-at-end): extend brk.
 *   4. Fallback: allocate new block, copy, free old.
 */
void *
mm_realloc(void *ptr, size_t size)
{
	size_t asize, oldsize, newsize, extend_size;
	void  *next, *next_next, *rem, *newptr;
	bool   next_alloc;

	if (size == 0) {
		mm_free(ptr);
		return NULL;
	}
	if (ptr == NULL)
		return mm_malloc(size);

	/* Compute adjusted target size. */
	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + DSIZE + (DSIZE - 1)) / DSIZE);

	oldsize = GET_SIZE(HDRP(ptr));

	if (asize == oldsize)
		return ptr;

	/* --- Case 1: shrink --- */
	if (asize < oldsize) {
		if ((oldsize - asize) >= (2 * DSIZE)) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			rem = NEXT_BLKP(ptr);
			PUT(HDRP(rem), PACK(oldsize - asize, 0));
			PUT(FTRP(rem), PACK(oldsize - asize, 0));
			coalesce(rem);
		}
		return ptr;
	}

	/* asize > oldsize from here on. */
	next       = NEXT_BLKP(ptr);
	next_alloc = GET_ALLOC(HDRP(next));

	/* --- Case 2: grow into free next block --- */
	if (!next_alloc) {
		size_t next_size = GET_SIZE(HDRP(next));
		newsize = oldsize + next_size;

		if (newsize >= asize) {
			remove_free(next);
			if ((newsize - asize) >= (2 * DSIZE)) {
				PUT(HDRP(ptr), PACK(asize, 1));
				PUT(FTRP(ptr), PACK(asize, 1));
				rem = NEXT_BLKP(ptr);
				PUT(HDRP(rem), PACK(newsize - asize, 0));
				PUT(FTRP(rem), PACK(newsize - asize, 0));
				insert_free(rem);
			} else {
				PUT(HDRP(ptr), PACK(newsize, 1));
				PUT(FTRP(ptr), PACK(newsize, 1));
			}
			return ptr;
		}

		/* Next block is free but too small; extend if it borders the epilogue. */
		next_next = NEXT_BLKP(next);
		if (GET_SIZE(HDRP(next_next)) == 0) {
			extend_size = asize - newsize;
			if (mem_sbrk(extend_size) != (void *)-1) {
				remove_free(next);
				newsize += extend_size;
				if ((newsize - asize) >= (2 * DSIZE)) {
					PUT(HDRP(ptr), PACK(asize, 1));
					PUT(FTRP(ptr), PACK(asize, 1));
					rem = NEXT_BLKP(ptr);
					PUT(HDRP(rem), PACK(newsize - asize, 0));
					PUT(FTRP(rem), PACK(newsize - asize, 0));
					insert_free(rem);
				} else {
					PUT(HDRP(ptr), PACK(newsize, 1));
					PUT(FTRP(ptr), PACK(newsize, 1));
				}
				PUT(HDRP(NEXT_BLKP(ptr)), PACK(0, 1)); /* new epilogue */
				return ptr;
			}
		}
	}

	/* --- Case 3: next is the epilogue – just extend the heap --- */
	if (next_alloc && GET_SIZE(HDRP(next)) == 0) {
		extend_size = asize - oldsize;
		if (mem_sbrk(extend_size) != (void *)-1) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			PUT(HDRP(NEXT_BLKP(ptr)), PACK(0, 1)); /* new epilogue */
			return ptr;
		}
	}

	/* --- Case 4: fall back to allocate-copy-free --- */
	newptr = mm_malloc(size);
	if (newptr == NULL)
		return NULL;
	memcpy(newptr, ptr, oldsize - DSIZE);   /* copy payload only */
	mm_free(ptr);
	return newptr;
}

/* ------------------------------------------------------------------ */
/*                     Internal helper routines                        */
/* ------------------------------------------------------------------ */

/*
 * coalesce - Merge bp with any adjacent free blocks.
 *
 * Removes adjacent free blocks from their lists, merges, and re-inserts.
 * Returns the (possibly larger) coalesced block pointer.
 */
static void *
coalesce(void *bp)
{
	void  *prev_bp   = PREV_BLKP(bp);
	void  *next_bp   = NEXT_BLKP(bp);
	bool   prev_alloc = GET_ALLOC(FTRP(prev_bp));
	bool   next_alloc = GET_ALLOC(HDRP(next_bp));
	size_t size       = GET_SIZE(HDRP(bp));

	if (prev_alloc && next_alloc) {
		/* Case 1: both neighbors allocated – nothing to merge */

	} else if (prev_alloc && !next_alloc) {
		/* Case 2: next block is free */
		remove_free(next_bp);
		size += GET_SIZE(HDRP(next_bp));
		PUT(HDRP(bp), PACK(size, 0));
		PUT(FTRP(bp), PACK(size, 0));

	} else if (!prev_alloc && next_alloc) {
		/* Case 3: prev block is free */
		remove_free(prev_bp);
		size += GET_SIZE(HDRP(prev_bp));
		PUT(FTRP(bp),      PACK(size, 0));
		PUT(HDRP(prev_bp), PACK(size, 0));
		bp = prev_bp;

	} else {
		/* Case 4: both neighbors are free */
		remove_free(prev_bp);
		remove_free(next_bp);
		size += GET_SIZE(HDRP(prev_bp)) + GET_SIZE(HDRP(next_bp));
		PUT(HDRP(prev_bp), PACK(size, 0));
		PUT(FTRP(next_bp), PACK(size, 0));
		bp = prev_bp;
	}

	insert_free(bp);
	return bp;
}

/*
 * extend_heap - Extend the heap by `words` words and return the new free block.
 */
static void *
extend_heap(size_t words)
{
	size_t size;
	void  *bp;

	/* Round up to an even number of words for alignment. */
	size = (words % 2) ? (words + 1) * WSIZE : words * WSIZE;
	if ((bp = mem_sbrk(size)) == (void *)-1)
		return NULL;

	PUT(HDRP(bp),            PACK(size, 0)); /* Free block header  */
	PUT(FTRP(bp),            PACK(size, 0)); /* Free block footer  */
	PUT(HDRP(NEXT_BLKP(bp)), PACK(0, 1));   /* New epilogue header */

	/* Coalesce with previous block if it is free. */
	return coalesce(bp);
}

/*
 * find_fit - Find the first free block of at least asize bytes.
 *
 * Searches from the smallest fitting size class upward.
 */
static void *
find_fit(size_t asize)
{
	for (int c = get_class(asize); c < NUM_CLASSES; c++) {
		for (void *bp = free_lists[c]; bp != NULL; bp = NEXT_FREE(bp)) {
			if (GET_SIZE(HDRP(bp)) >= asize)
				return bp;
		}
	}
	return NULL;
}

/*
 * place - Allocate asize bytes at bp, splitting if the remainder is usable.
 */
static void
place(void *bp, size_t asize)
{
	size_t csize = GET_SIZE(HDRP(bp));

	remove_free(bp);

	if ((csize - asize) >= (2 * DSIZE)) {
		/* Split: allocate front half, free the remainder. */
		PUT(HDRP(bp), PACK(asize, 1));
		PUT(FTRP(bp), PACK(asize, 1));
		void *next_bp = NEXT_BLKP(bp);
		PUT(HDRP(next_bp), PACK(csize - asize, 0));
		PUT(FTRP(next_bp), PACK(csize - asize, 0));
		insert_free(next_bp);
	} else {
		/* No split: use the entire block. */
		PUT(HDRP(bp), PACK(csize, 1));
		PUT(FTRP(bp), PACK(csize, 1));
	}
}

/* ------------------------------------------------------------------ */
/*                    Heap consistency checker                         */
/* ------------------------------------------------------------------ */

static void
checkblock(void *bp)
{
	if ((uintptr_t)bp % DSIZE)
		printf("Error: %p is not doubleword aligned\n", bp);
	if (GET(HDRP(bp)) != GET(FTRP(bp)))
		printf("Error: header does not match footer at %p\n", bp);
}

void
checkheap(bool verbose)
{
	void *bp;

	if (verbose)
		printf("Heap (%p):\n", heap_listp);

	if (GET_SIZE(HDRP(heap_listp)) != DSIZE || !GET_ALLOC(HDRP(heap_listp)))
		printf("Bad prologue header\n");
	checkblock(heap_listp);

	for (bp = heap_listp; GET_SIZE(HDRP(bp)) > 0; bp = NEXT_BLKP(bp)) {
		if (verbose)
			printblock(bp);
		checkblock(bp);
		/* Check for consecutive free blocks (missed coalescing). */
		if (!GET_ALLOC(HDRP(bp)) && !GET_ALLOC(HDRP(NEXT_BLKP(bp))))
			printf("Error: consecutive free blocks at %p and %p\n",
			    bp, NEXT_BLKP(bp));
	}

	if (verbose)
		printblock(bp);
	if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
		printf("Bad epilogue header\n");

	/* Verify every block in each free list is actually free. */
	for (int c = 0; c < NUM_CLASSES; c++) {
		for (void *fp = free_lists[c]; fp != NULL; fp = NEXT_FREE(fp)) {
			if (GET_ALLOC(HDRP(fp)))
				printf("Error: allocated block %p in free list %d\n",
				    fp, c);
			if (PREV_FREE(fp) != NULL &&
			    NEXT_FREE(PREV_FREE(fp)) != fp)
				printf("Error: free list %d inconsistent at %p\n",
				    c, fp);
		}
	}
}

static void
printblock(void *bp)
{
	size_t hsize = GET_SIZE(HDRP(bp));
	bool   halloc = GET_ALLOC(HDRP(bp));
	size_t fsize = GET_SIZE(FTRP(bp));
	bool   falloc = GET_ALLOC(FTRP(bp));

	if (hsize == 0) {
		printf("%p: end of heap\n", bp);
		return;
	}
	printf("%p: header: [%zu:%c] footer: [%zu:%c]\n", bp,
	    hsize, (halloc ? 'a' : 'f'),
	    fsize, (falloc ? 'a' : 'f'));
}

