/*
 * place - Allocate asize bytes at bp, splitting if the remainder is usable.
 *
 * Placement policy:
 *   - Small blocks (asize <= SMALL_THRESHOLD): allocate from the END of bp,
 *     leaving the front free.  This preserves a contiguous free region at the
 *     low-address side so that a growing large block (e.g. repeated realloc)
 *     can absorb it in place via coalesce, and prevents small blocks from
 *     fragmenting large free regions.
 *   - Large blocks: allocate from the FRONT (standard approach).
 *
 * Returns the payload pointer of the newly allocated block.
 */
static void *
place(void *bp, size_t asize)
{
	size_t csize     = GET_SIZE(HDRP(bp));
	size_t remainder = csize - asize;

	remove_free(bp);

	if (remainder >= (2 * DSIZE)) {
		if (asize <= SMALL_THRESHOLD) {
			/*
			 * Small block: put at END of the free region.
			 * Free portion stays at the front (low address).
			 */
			void *alloc_bp = (char *)bp + remainder;
			PUT(HDRP(bp),       PACK(remainder, 0));
			PUT(FTRP(bp),       PACK(remainder, 0));
			PUT(HDRP(alloc_bp), PACK(asize, 1));
			PUT(FTRP(alloc_bp), PACK(asize, 1));
			insert_free(bp);
			return alloc_bp;
		} else {
			/*
			 * Large block: put at FRONT (standard split).
			 * Free remainder goes to the back.
			 */
			PUT(HDRP(bp), PACK(asize, 1));
			PUT(FTRP(bp), PACK(asize, 1));
			void *next_bp = NEXT_BLKP(bp);
			PUT(HDRP(next_bp), PACK(remainder, 0));
			PUT(FTRP(next_bp), PACK(remainder, 0));
			insert_free(next_bp);
			return bp;
		}
	} else {
		/* No split: use the entire block. */
		PUT(HDRP(bp), PACK(csize, 1));
		PUT(FTRP(bp), PACK(csize, 1));
		return bp;
	}
}

